class Solution:
    def longestSubsequence(self, s: str, k: int) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        for i in range(n):
            if s[i] == '1':
                dp[i + 1] = max(dp[i], dp[i - 1] + 1) if i > 0 else 1
            else:
                dp[i + 1] = dp[i]
        res = 0
        for i in range(n, -1, -1):
            if int(''.join(s[i:]), 2) <= k:
                res = max(res, dp[i])
            else:
                break
        return res
